#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e5 + 5;
int n, q, m, a[MAXN], dep[MAXN], f[MAXN][65];
vector <int> p[MAXN];
void dfs(int u)
{
	for (auto v : p[u])
	{
		dep[v] = dep[u] + 1;
		dfs(v);
	}
}
void init()
{
	for (int j = 1; (1 << j) <= n; ++j )
		for (int i = 1; i < n; ++i )
			f[i][j] = f[f[i][j - 1]][j - 1];
}
int lca(int u, int v)
{
	if (dep[u] < dep[v])swap(u, v);
	int i = -1, j;
	while ((1 << (i + 1)) <= dep[u])++i ;
	for (j = i; j >= 0; --j )
		if (dep[u] - (1 << j) >= dep[v])u = f[u][j];
	if (u == v)return u;
	for (j = i; j >= 0; --j )
	{
		if (f[u][j] != f[v][j])
		{
			u = f[u][j];
			v = f[v][j];
		}
	}
	return f[u][0];
}
int main(void)
{
	cin >> n;
	for (int i = 1, x; i < n; ++i )
	{
		cin >> x;
		p[x].push_back(i);
		f[i][0] = x;
	}
	dfs(0);
	init();
	cin >> q;
	while (q--)
	{
		cin >> m;
		for (int i = 1; i <= m; ++i)cin >> a[i];
		int i = 3, x = lca(a[1], a[2]);
		while (i <= m)
		{
			x = lca(x, a[i]);
			++i;
		}
		cout << x << '\n';
	}
	return false;
}
